import pandas as pd
from sqlalchemy import text

# 查看所有站点名称，搜索包含"lig"或"理工"的
query_all = text("SELECT id, name FROM air_quality_station ORDER BY id")
all_stations = pd.read_sql(query_all, engine)

# 搜索包含"lig"的
for idx, row in all_stations.iterrows():
    name = row['name']
    if 'lig' in name.lower():
        print(f"Found 'lig': id={row['id']}, name={name}")

# 搜索包含"理工"的
for idx, row in all_stations.iterrows():
    name = row['name']
    if '理工' in name:
        print(f"Found '理工': id={row['id']}, name={name}")

# 搜索包含"ligong"的
for idx, row in all_stations.iterrows():
    name = row['name']
    if 'ligong' in name.lower():
        print(f"Found 'ligong': id={row['id']}, name={name}")

